#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y; scanf("%lld %lld", &X, &Y);
        if (X >= 2 * Y) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

